import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./ConsultancyPage.css";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000/api";

function ConsultancyPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState("");
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // 🔹 NEW: fetch doctors from backend (admin-managed)
  const [doctorsList, setDoctorsList] = useState([]);
  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/public/doctors`);
        const data = await res.json();
        setDoctorsList(Array.isArray(data) ? data : []);
      } catch (_) {
        setDoctorsList([]);
      }
    })();
  }, []);

  // group dynamically by specialty to keep your existing UI
  const doctorsData = useMemo(() => {
    if (!doctorsList.length) return {};
    return doctorsList.reduce((acc, d) => {
      const key = d.specialty || "General";
      (acc[key] = acc[key] || []).push({
        name: d.name,
        img:
          d.img ||
          "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
        details: d.details || (d.experience ? `${d.experience}+ years experience` : "Experienced doctor"),
        languages: Array.isArray(d.languages) ? `Speaks ${d.languages.join(", ")}` : "",
        fee: d.fee ? `₹${d.fee}` : "₹700",
        category: key,
      });
      return acc;
    }, {});
  }, [doctorsList]);

  // Flatten list for search suggestions
  const allDoctors = useMemo(
    () =>
      Object.keys(doctorsData).flatMap((category) =>
        doctorsData[category].map((doc) => ({
          ...doc,
          category,
        }))
      ),
    [doctorsData]
  );

  // Filter suggestions
  const suggestions = allDoctors.filter((doc) =>
    doc.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Handle suggestion click → expand correct category
  const handleSuggestionClick = (doctor) => {
    setActiveDropdown(doctor.category);
    setSearchQuery(doctor.name);
    setShowSuggestions(false);
    const section = document.getElementById(doctor.category.replace(/\s+/g, "-"));
    if (section) {
      section.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <div className="consultancy-page">
      {/* === Header Section === */}
      <div className="consultancy-header">
        <h1>Our Doctors</h1>
        <p>
          We have handpicked some of the best doctors in key specialties. Whether
          you’re looking for a General Physician or a Pediatrician — you’ll find
          trusted professionals here.
        </p>

        {/* === Search Bar with Suggestions === */}
        <div className="search-container">
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search doctor name..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setShowSuggestions(true);
              }}
            />
            <button onClick={() => setShowSuggestions(false)}>Search</button>
          </div>

          {showSuggestions && searchQuery && (
            <ul className="suggestions-list">
              {suggestions.length > 0 ? (
                suggestions.map((doc, index) => (
                  <li key={index} onClick={() => handleSuggestionClick(doc)}>
                    <strong>{doc.name}</strong> <span>({doc.category})</span>
                  </li>
                ))
              ) : (
                <li className="no-suggestion">No doctor found</li>
              )}
            </ul>
          )}
        </div>
      </div>

      {/* === Doctor Sections === */}
      <div className="doctor-sections">
        {Object.keys(doctorsData).length ? (
          Object.keys(doctorsData).map((category, index) => (
            <div
              key={index}
              id={category.replace(/\s+/g, "-")}
              className="doctor-category"
            >
              <div
                className="category-header"
                onClick={() =>
                  setActiveDropdown(activeDropdown === category ? null : category)
                }
              >
                <h2>{category}</h2>
                <span
                  className={`arrow ${activeDropdown === category ? "open" : ""}`}
                >
                  ▼
                </span>
              </div>

              {activeDropdown === category && (
                <div className="doctor-list">
                  {doctorsData[category].map((doc, i) => (
                    <div className="doctor-card" key={i}>
                      <img src={doc.img} alt={doc.name} />
                      <div className="doctor-info">
                        <h3>{doc.name}</h3>
                        <p>{doc.details}</p>
                        <p className="languages">{doc.languages}</p>
                        <div className="consultation">
                          <span>{doc.fee} per consultation</span>
                          <div className="buttons">
                            <button className="view-btn">View Profile</button>
                            <button className="book-btn">Book Appointment</button>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))
        ) : (
          <p style={{ padding: 20 }}>No doctors added yet.</p>
        )}
      </div>
    </div>
  );
}

export default ConsultancyPage;
